sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
    if (isLoading || newValue === '') {
        return;
    }
    var custid = g_form.getValue('number');
    //alert(custid);

	//Script include
    var ga = new GlideAjax('x_cpszo_spoke.OfferTypeHelper');
    ga.addParam('sysparm_name', 'getOfferDefaults');
    ga.addParam('sys_parm_cust', custid);
    ga.getXMLAnswer(function(response) {
        var result = JSON.parse(response);
        //alert(result.offer_type);

        var amount = result.installment_amount;
        var formatted = amount.toLocaleString('en', {
            type: 'currency',
            currency: 'USD'
        });

        // var amount = parseFloat(g_form.getValue('installment_amount')) || 0;

        // // Format the amount as currency
        // var formatted = amount.toLocaleString('en', {
        //     type: 'currency',
        //     currency: 'USD'
        // });



        g_form.setValue('offer_type', result.offer_type);
        g_form.setValue('delinquency_status', result.delinquency_status);
        g_form.setValue('installment_amount', formatted);
		g_form.setValue('acceptance_date', g_scratchpad.acceptance_date);


        //Credit Card Upsell
        if (result.valid_offer_types) {
            g_form.clearOptions('offer_type');
            result.valid_offer_types.forEach(function(opt) {
                g_form.addOption('offer_type', opt.value, opt.label);
            });

            // Optionally re-set the selected value after repopulating
            g_form.setValue('offer_type', result.offer_type);
        }
        ////Credit Card Upsell ends here

        /*
            if (result.risk=="high") {
                g_form.setValue('u_offer_type', waiver);
            } else if(result.risk=="medium") {
                g_form.setValue('u_offer_type',extension);
            } else{
        		g_form.setValue('u_offer_type',emi adjustment);
        	}*/

    });

    //Type appropriate comment here, and begin script below

}
